var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아직 버틸 수 있어…… 아니, 버텨야 해!","JPN":"まだ耐えられる……いや、耐えないと！","ENG":"I can still keep fighting… No, I must!","TWN":"我還撐得下去……不，是一定要撐下去！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가 쓰러지면…… 선배가……","JPN":"私が倒れたら……先輩が……","ENG":"If I fall… Shiyoon's in danger…","TWN":"我倒下去的話……那前輩他……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭, 제기랄……!","JPN":"く、くそ……！","ENG":"Hngh... Damn it!","TWN":"唔！可惡……！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"역시, 무리해서 일깨운 용혈의 힘은 이 정도군요.","JPN":"やはり、無理して目覚めさせた龍血の力ではこの程度ですね。","ENG":"Alas, so this is the extent of the power forcibly drawn from the Dragon Blood.","TWN":"果然，勉強喚醒的龍血力量就只有這樣。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아직 자신이 무엇인지도 모르는 어린 늑대한테조차 고전하다니.","JPN":"まだ自分が何者かも気づいていない幼い狼に苦戦するなんて。","ENG":"He struggles against a mere Wolf pup who doesn't even know what she is.","TWN":"對手不過是個連自己是誰都還搞不清楚地幼狼，這樣也陷入苦戰。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"당신…… 설마 일부러 숨어 있다가 나타난 건가요?","JPN":"あなたは……もしかしてわざと隠れていたんですか？","ENG":"Were you hiding all this time?","TWN":"你……該不會是故意躲起來的吧？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양을 쓰러트리고 싶다면 어째서 구경만 하는 거죠? 지금이 적기 아닌가요?","JPN":"ミナさんを倒したいならどうして何もしないんですか？　今が好機なのでは？","ENG":"Why are you just watching if you want to take down Mina? Wouldn't this be the perfect time to strike?","TWN":"你不是想打倒米娜嗎？怎麼可以只在旁邊偷看呢？現在不是好機會嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"말했을 텐데요. 이건 용의 탄생을 위해 제물을 바치는 <color=#ffd34c>의식</color>입니다.","JPN":"言ったはずです。これは龍の誕生のために生贄を捧げる<color=#ffd34c>儀式</color>です。","ENG":"Like I said... This is simply a <color=#ffd34c>ritual</color> to offer a sacrifice for the birth of the Dragon.","TWN":"我剛不是說過，獻祭<color=#ffd34c>儀式</color>目的，是要讓龍能夠誕生。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제 손으로 저 늑대를 죽여 봐야 아무런 의미도 없지요.","JPN":"私の手であの狼を殺しても何の意味もありません。","ENG":"Killing the Wolf myself will do no good.","TWN":"那隻狼是不是我親手殺的根本沒差。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러면 그것과…… 저 괴물의 목소리가…… 무슨 관련이 있는 거죠?","JPN":"じゃあアレと……あの化け物の声が……何の関係があるのですか？","ENG":"Then… what's that monster's voice got to do with anything?","TWN":"這麼說來……這和剛才那怪物的聲音……有什麼關聯囉？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저런. 부모님의 목소리를 듣고 놀라셨나 보군요. 이방인이여.","JPN":"ああ、両親の声を聞いて驚いたようですね、異邦人よ。","ENG":"Ah. The voice of your parents must have startled you, outsider.","TWN":"哎呀～剛剛聽到父母親的聲音嚇一跳嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용혈의 계승자는 번뇌에서 벗어날 수 없습니다.","JPN":"龍血の継承者は煩悩から逃れられません。","ENG":"The heir to the Dragon Blood cannot escape their Kleshas.","TWN":"龍血的繼承者無法脫離煩惱，"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 번뇌라는 것은 삶의 끝을 지나, 죽음 이후에도 헤어날 수 없는 저주죠.","JPN":"そして煩悩というものは人生の果てを過ぎ、死を迎えても抜け出せない呪いです。","ENG":"Kleshas are a curse that extends beyond a single lifetime, beyond death itself.","TWN":"而且就算你走到人生的盡頭，死去後也無法擺脫。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"설마……","JPN":"まさか……","ENG":"You mean…","TWN":"難道……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"용혈의 힘은 대를 이어갈수록 강해집니다.","JPN":"龍血の力は世代を継ぐことで強くなります。","ENG":"The power of the Dragon Blood grows more potent with each generation.","TWN":"龍血的力量越是傳承下去就會越強大。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그리고 이 세상에…… 대가가 없는 힘은 없습니다.","JPN":"そしてこの世に……代償のない力はありません。","ENG":"And in this world… there is no power without a price.","TWN":"而且在這個世界上……所有的力量都是需要付代價的。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};